select.where:
 and gs.goods_id = #{goodsId}
 and gs.sku_attr = #{skuAttr}
 and gs.sku_code = #{skuCode}
 and gs.unit = #{unit}
 and gs.stock_num = #{stockNum}
 and gs.safe_stock = #{safeStock}
 and gs.purchase_price = #{purchasePrice}
 and gs.sale_price = #{salePrice}
 and gs.pic_url = #{picUrl}
 and gs.status = #{status}
and gs.del_flag = '0'
